namespace sv_14fb9c6a722b42088c450be517515427.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_14fb9c6a722b42088c450be517515427.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-white text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarRating(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}

@using sv_14fb9c6a722b42088c450be517515427.Services

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="product"
                         OnSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@using sv_14fb9c6a722b42088c450be517515427.Services

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input"
                       type="checkbox"
                       id="@($"cat-{category}")"
                       checked="@_selectedCategories.Contains(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm"
                   placeholder="Min" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm"
                   placeholder="Max" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@page "/catalog"
@using sv_14fb9c6a722b42088c450be517515427.Components.Catalog
@using sv_14fb9c6a722b42088c450be517515427.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="_categories"
                            OnFilterApplied="HandleFilterApplied" />
        </div>
        <div class="col-md-9">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result?.TotalCount ?? 0"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products...</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="alert alert-info text-center" role="status">
                    No products found. Try adjusting your filters.
                </div>
            }
            else
            {
                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (TotalPages > 1)
                {
                    <div class="mt-4">
                        <CatalogPagination CurrentPage="_currentPage"
                                           TotalPages="TotalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    /// <summary>
    /// Raised when a product card is clicked, allowing a parent layout or
    /// wrapper component to navigate to the product detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int TotalPages =>
        _result is null || _result.TotalCount == 0
            ? 1
            : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = _categories.Count == 0
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with a cart service when available
        await Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

